mapper.select:
SELECT oi.id AS orderItemId, oi.product_id AS productId, oi.quantity, oi.price, p.price AS originalPrice, p.name AS productName, p.brand AS productBrand, pi.image_url AS productImageUrl, opt.option_name AS optionName, o.id AS orderId, o.created_at AS orderDate, r.id AS reviewId, r.rating AS reviewRating, r.content AS reviewContent FROM petlog.order_item oi JOIN petlog.`order` o ON oi.order_id = o.id JOIN petlog.product p ON oi.product_id = p.id LEFT JOIN petlog.product_image pi ON pi.product_id = p.id AND pi.is_thumbnail = true LEFT JOIN petlog.`option` opt ON oi.option_id = opt.id LEFT JOIN petlog.review r ON r.order_item_id = oi.id WHERE o.user_id = #{userId}
AND o.created_at >= DATE_SUB(NOW(), INTERVAL 1 MONTH) AND o.created_at >= DATE_SUB(NOW(), INTERVAL 3 MONTH) AND o.created_at >= DATE_SUB(NOW(), INTERVAL 6 MONTH) AND o.created_at >= DATE_SUB(NOW(), INTERVAL 1 YEAR) AND o.created_at >= DATE_SUB(NOW(), INTERVAL 2 YEAR)
ORDER BY o.created_at DESC

SELECT oi.id, oi.product_id, oi.option_id, oi.quantity, oi.price, o.created_at AS orderDate, o.id AS orderId FROM order_item oi JOIN `order` o ON oi.order_id = o.id WHERE o.user_id = #{userId}
AND o.created_at >= DATE_SUB(NOW(), INTERVAL 1 MONTH) AND o.created_at >= DATE_SUB(NOW(), INTERVAL 3 MONTH) AND o.created_at >= DATE_SUB(NOW(), INTERVAL 6 MONTH) AND o.created_at >= DATE_SUB(NOW(), INTERVAL 1 YEAR) AND o.created_at >= DATE_SUB(NOW(), INTERVAL 2 YEAR)
ORDER BY o.created_at DESC

SELECT r.*
FROM `petlog`.`reservation` r
         JOIN `petlog`.`store` s ON r.store_id = s.store_id
WHERE r.reservation_id = #{reservationId}
  AND s.user_id = #{userId}
